    const similarity = typeof memory.similarity === 'number' ? memory.similarity : 0;
    return {
      ...memory,
      lexical_overlap: lexicalOverlap,
      passes_relevance: similarity >= similarityThreshold || lexicalOverlap >= 1,
    };
  })
  .sort((left, right) => {
    if (base.project_slug) {
      const leftProject = left.project_slug === base.project_slug ? 1 : 0;
      const rightProject = right.project_slug === base.project_slug ? 1 : 0;
